  console.log("NowTabKey无效");
  localStorage.setItem("SearchTabKey", "Bing");
  NowTabKey.value = "Bing";
}

if (!searchTabs.value.includes(NowTabKey.value)) {
  NowTabKey.value = searchTabs.value[searchTabs.value.length - 1];
}

